import{_ as e,o as a,c as t,ag as l}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"文字特辑","titleTemplate":"仅展示想要展示的一面","description":"","frontmatter":{"title":"文字特辑","titleTemplate":"仅展示想要展示的一面","layout":"doc","navbar":true,"sidebar":true,"aside":true,"footer":false,"lastUpdated":true},"headers":[],"relativePath":"hello-world.md","filePath":"hello-world.md","lastUpdated":null}'),r={name:"hello-world.md"};function o(d,p,s,i,n,_){return a(),t("div",null,[...p[0]||(p[0]=[l('<h1 id="谢谢支持" tabindex="-1">谢谢支持 <a class="header-anchor" href="#谢谢支持" aria-label="Permalink to &quot;谢谢支持&quot;">​</a></h1><p>只是随便写写，是写的很烂的东西呢。 感谢你的观看！</p><h3 id="_2026愚人节" tabindex="-1">2026愚人节 <a class="header-anchor" href="#_2026愚人节" aria-label="Permalink to &quot;2026愚人节&quot;">​</a></h3><p>如果可以的话，可以一直沐浴着月光吗？</p><p>远远明亮于星星的光芒，却也柔和地照耀着我。</p><p>无论何时都是那么的温柔。</p><p>可是，讨厌的太阳照耀着月亮。</p><p>借走光芒的月亮才如此闪闪发亮。</p><p>真是纠结呢。</p><p>于是，喜欢着月亮的我独自沐浴着月光。</p><p>喜欢。</p><p>得不到。</p><p>喜欢。</p><p>没有理由。</p><p>喜欢。</p><p>却也嫌恶。</p><p>自暴自弃般的我讨厌着太阳。</p><p>炽热的光芒暴戾的让人睁不开眼睛。</p><p>借走光芒的月亮如此温柔。</p><p>明亮也会胜过繁星。</p><p>若是没有太阳该多好？</p><p>其实心底也清楚没有太阳会怎么样。</p><p>假若白昼中也能沐浴月光该多好。</p><p>谎言的日子中，用温柔的话语说出实话。</p><p>喜欢。</p><p>厌恶着。</p><p>喜欢。</p><p>躲避着。</p><p>喜欢。</p><p>无法直面。</p><p>喜欢。</p><p>没有理由。</p><p>喜欢。</p><p>好想得到。</p><p>喜欢。</p><p>不能诉说。</p>',36)])])}const u=e(r,[["render",o]]);export{h as __pageData,u as default};
